int segPins[7] = {5, 6, 7, 8, 9, 10, 11};
int btnAddPin = 2;
int btnSubPin = 4;
int count = 0;
int lastAddState = HIGH;
int lastSubState = HIGH;

// Digit patterns for 7-segment (a,b,c,d,e,f,g)
// Common cathode: 1=on, 0=off
void setDigit(int digit) {
  int patterns[10][7] = {0,0,0,0,0,0,0}; // placeholder

  if (digit == 0) { digitalWrite(5,HIGH); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,HIGH); digitalWrite(9,HIGH); digitalWrite(10,HIGH); digitalWrite(11,LOW); }
  else if (digit == 1) { digitalWrite(5,LOW); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,LOW); digitalWrite(9,LOW); digitalWrite(10,LOW); digitalWrite(11,LOW); }
  else if (digit == 2) { digitalWrite(5,HIGH); digitalWrite(6,HIGH); digitalWrite(7,LOW); digitalWrite(8,HIGH); digitalWrite(9,HIGH); digitalWrite(10,LOW); digitalWrite(11,HIGH); }
  else if (digit == 3) { digitalWrite(5,HIGH); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,HIGH); digitalWrite(9,LOW); digitalWrite(10,LOW); digitalWrite(11,HIGH); }
  else if (digit == 4) { digitalWrite(5,LOW); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,LOW); digitalWrite(9,LOW); digitalWrite(10,HIGH); digitalWrite(11,HIGH); }
  else if (digit == 5) { digitalWrite(5,HIGH); digitalWrite(6,LOW); digitalWrite(7,HIGH); digitalWrite(8,HIGH); digitalWrite(9,LOW); digitalWrite(10,HIGH); digitalWrite(11,HIGH); }
  else if (digit == 6) { digitalWrite(5,HIGH); digitalWrite(6,LOW); digitalWrite(7,HIGH); digitalWrite(8,HIGH); digitalWrite(9,HIGH); digitalWrite(10,HIGH); digitalWrite(11,HIGH); }
  else if (digit == 7) { digitalWrite(5,HIGH); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,LOW); digitalWrite(9,LOW); digitalWrite(10,LOW); digitalWrite(11,LOW); }
  else if (digit == 8) { digitalWrite(5,HIGH); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,HIGH); digitalWrite(9,HIGH); digitalWrite(10,HIGH); digitalWrite(11,HIGH); }
  else if (digit == 9) { digitalWrite(5,HIGH); digitalWrite(6,HIGH); digitalWrite(7,HIGH); digitalWrite(8,HIGH); digitalWrite(9,LOW); digitalWrite(10,HIGH); digitalWrite(11,HIGH); }
}

void setup() {
  for (int i = 0; i < 7; i++) {
    pinMode(segPins[i], OUTPUT);
  }
  pinMode(btnAddPin, INPUT_PULLUP);
  pinMode(btnSubPin, INPUT_PULLUP);
  setDigit(0);
}

void loop() {
  int addState = digitalRead(btnAddPin);
  int subState = digitalRead(btnSubPin);

  if (addState == LOW && lastAddState == HIGH) {
    count++;
    if (count > 9) count = 0;
    setDigit(count);
  }

  if (subState == LOW && lastSubState == HIGH) {
    count--;
    if (count < 0) count = 9;
    setDigit(count);
  }

  lastAddState = addState;
  lastSubState = subState;

  delay(20);
}

